export interface BillResult {
  originalTotal: number;
  taxTotal: number;
  tipTotal: number;
  discountTotal: number;
  grandTotal: number;
  shares: PersonShare[];
}

export class BillError extends Error {
  constructor(msg: string) {
    super(msg);
    this.name = "BillError";
    Object.setPrototypeOf(this, BillError.prototype);
  }
